import { Component } from "react";

const styles = {
    off: {
        justifyContent: 'flex-start'
    },
    on: {
        justifyContent: 'flex-end'
    }
}

class Switch extends Component {
    render(){
        const { cambiarTema, temaOscuro } = this.props
        if (temaOscuro){
            return (
                <div style={styles.off} className="contenedor-switch">
                    <button onClick={cambiarTema} className="switch">A</button>
                </div>
            )
        }
        else {
            return (
                <div style={styles.on} className="contenedor-switch">
                    <button onClick={cambiarTema} className="switch">B</button>
                </div>
            )
        }

    }
}

export default Switch
